Resistance network


Code
{
  // Resistor elements: conv_L, layer 1, layer 2, layer 3, conv_R
  const elements = [
    { label: "1/hₗ",   formula: "1/h_L",   value: R_conv_L, color: "#d6eaf8" },
    { label: "L₁/k₁", formula: "L₁/k₁", value: L1/k1,    color: layer_colors[0] },
    { label: "L₂/k₂", formula: "L₂/k₂", value: L2/k2,    color: layer_colors[1] },
    { label: "L₃/k₃", formula: "L₃/k₃", value: L3/k3,    color: layer_colors[2] },
    { label: "1/hᴿ",   formula: "1/h_R",   value: R_conv_R, color: "#d6eaf8" },
  ]

  const BW = 80, gap = 18, cy = 60
  const termPad = 44   // space for T∞ labels at each end
  const total_w = termPad + elements.length * BW + (elements.length - 1) * gap + termPad
  const svgH = 110

  // Draw zigzag polyline for a resistor body
  function zigzagPts(x0, y, w) {
    const stub = 10, n = 6, amp = 8
    const bodyW = w - 2 * stub
    const dx = bodyW / n
    let pts = `${x0},${y} ${x0 + stub},${y}`
    for (let i = 0; i &lt; n; i++) {
      const xp = x0 + stub + (i + 0.5) * dx
      const yp = y + (i % 2 === 0 ? -amp : amp)
      pts += ` ${xp},${yp}`
    }
    pts += ` ${x0 + w - stub},${y} ${x0 + w},${y}`
    return pts
  }

  let svg = `&lt;svg viewBox="0 0 ${total_w} ${svgH}" style="width:100%;max-width:700px;overflow:visible;" aria-label="Thermal resistance network"&gt;`

  // Left terminal: dot + T∞,L label
  const x0_wire = termPad
  svg += `&lt;circle cx="${x0_wire}" cy="${cy}" r="4" fill="#c0392b"/&gt;`
  svg += `&lt;text x="${x0_wire - 8}" y="${cy + 5}" text-anchor="end" font-size="13" font-family="Georgia,serif" fill="#c0392b"&gt;T∞,L&lt;/text&gt;`

  // Wire from left terminal to first resistor
  const x_first = x0_wire
  svg += `&lt;line x1="${x0_wire}" y1="${cy}" x2="${x0_wire}" y2="${cy}" stroke="#555" stroke-width="1.5"/&gt;`

  elements.forEach((el, i) =&gt; {
    const x = x0_wire + i * (BW + gap)

    // Connecting wire before this element
    if (i === 0) {
      // already at terminal
    } else {
      svg += `&lt;line x1="${x - gap}" y1="${cy}" x2="${x}" y2="${cy}" stroke="#555" stroke-width="1.5"/&gt;`
    }

    // Zigzag resistor
    svg += `&lt;polyline points="${zigzagPts(x, cy, BW)}" fill="none" stroke="${el.color === "#d6eaf8" ? "#3498db" : "#2c3e50"}" stroke-width="2" stroke-linejoin="round"/&gt;`

    // Label above
    svg += `&lt;text x="${x + BW/2}" y="${cy - 20}" text-anchor="middle" font-size="12" font-family="Georgia,serif" fill="#333"&gt;${el.label}&lt;/text&gt;`

    // Value below
    svg += `&lt;text x="${x + BW/2}" y="${cy + 22}" text-anchor="middle" font-size="11" font-family="Georgia,serif" fill="#555"&gt;${el.value.toFixed(4)}&lt;/text&gt;`
    svg += `&lt;text x="${x + BW/2}" y="${cy + 34}" text-anchor="middle" font-size="9"  font-family="Georgia,serif" fill="#888"&gt;m²·K/W&lt;/text&gt;`
  })

  // Wire after last element to right terminal
  const x_last_end = x0_wire + elements.length * BW + (elements.length - 1) * gap
  const x_r_term = x_last_end
  svg += `&lt;line x1="${x_last_end - 0}" y1="${cy}" x2="${x_r_term}" y2="${cy}" stroke="#555" stroke-width="1.5"/&gt;`

  // Right terminal: dot + T∞,R label
  svg += `&lt;circle cx="${x_r_term}" cy="${cy}" r="4" fill="#c0392b"/&gt;`
  svg += `&lt;text x="${x_r_term + 8}" y="${cy + 5}" text-anchor="start" font-size="13" font-family="Georgia,serif" fill="#c0392b"&gt;T∞,R&lt;/text&gt;`

  // R_tot summary below
  svg += `&lt;text x="${total_w/2}" y="${svgH - 4}" text-anchor="middle" font-size="12" font-family="Georgia,serif" fill="#333"&gt;R″_tot = ${R_tot.toFixed(4)} m²·K/W&lt;/text&gt;`

  svg += `&lt;/svg&gt;`
  return html`${svg}`
}

Interactive demo
Below we’ve got a plot of \(T(x)\) and sliders that set the values of \(h\), …, . Before adjusting any of the sliders, let’s check our intuition: If we increase the thermal conductivity \(k\), what do we expect to happen to the temperature profile? What about increasing \(h\)? Increasing \(L\)? Form a hypothesis for each, then test it.


